      "keystrokes": "cd /app && python3 - <<'PY'\nfrom pathlib import Path\nimport re,struct\ndata=Path('/app/mystery').read_bytes()\nfiles=['main2.txt','sphere_obj.txt','plane_obj.txt','sky_obj.txt','write_image_obj.txt']\npat=re.compile(r'# ([0-9a-f]+) <([^>]+)>')\nfor fn in files:\n    print('=== refs',fn)\n    seen=set()\n    for line in Path('/app/'+fn).read_text().splitlines():\n        m=pat.search(line)\n        if not m: continue\n        addr=int(m.group(1),16)\n        if addr in seen: continue\n        seen.add(addr)\n        off=addr-0x400000\n        vals=[]\n        if 0<=off and off+16<=len(data):\n            for j in range(0,16,4):\n                f=struct.unpack('<f',data[off+j:off+j+4])[0]\n                vals.append(f'{f:.7g}')\n            txt=''.join(chr(x) if 32<=x<127 else '.' for x in data[off:off+16])\n        else:\n            txt='OUT'\n        print(f'{addr:08x} {m.group(2)}: {txt} | '+' '.join(vals))\nPY\n",
      "duration": 1.0
    },
